function pgEscape(v) {
  if (v === null || v === undefined) return 'NULL';
  if (typeof v === 'number') return Number.isFinite(v) ? String(v) : '0';
  if (typeof v === 'boolean') return v ? 'TRUE' : 'FALSE';
  const s = String(v);
  return "'" + s.replace(/'/g, "''") + "'";
}

function stableHash(input) {
  const s = String(input || '');
  const seeds = [0x811c9dc5, 0x45d9f3b, 0x27d4eb2d, 0x165667b1];
  return seeds.map((seed, i) => {
    let h = seed ^ s.length ^ i;
    for (let n = 0; n < s.length; n++) {
      h ^= s.charCodeAt(n);
      h = Math.imul(h, 16777619);
    }
    return (h >>> 0).toString(16).padStart(8, '0');
  }).join('');
}

function pgTimestamp(v) {
  const d = new Date(v || Date.now());
  const iso = Number.isNaN(d.getTime()) ? new Date().toISOString() : d.toISOString();
  return pgEscape(iso) + '::timestamp';
}

function pgNumeric(v, fallback = 0) {
  const n = Number(v);
  return Number.isFinite(n) ? String(n) : String(fallback);
}

function isEntryLevelTitle(title) {
  return /\b(junior|jr|graduate|new grad|entry level|early career|trainee|apprentice|associate)\b/i.test(String(title || ''));
}

function buildSql(o) {
  const cols = [
    'company', 'title', 'location', 'country', 'jd_full_text', 'original_url',
    'source', 'posted_date', 'match_score', 'job_type', 'is_graduate',
    'experience_years_max',
  ];
  const vals = [
    pgEscape(o.company || 'Unknown'),
    pgEscape(o.title || 'Untitled role'),
    pgEscape(o.location || o.country || 'Unknown'),
    pgEscape(o.country || 'IE'),
    pgEscape(o.jd_text || ''),
    pgEscape(o.url),
    pgEscape(String(o.source || 'unknown').slice(0, 50)),
    pgTimestamp(o.posted_at),
    pgNumeric(o.match_score, 0),
    pgEscape(o.remote_type || null),
    pgEscape(isEntryLevelTitle(o.title)),
    '0',
  ];
  const returning = [
    'id', 'title', 'company', 'location',
    'original_url AS url',
    'jd_full_text AS jd_text',
    'md5(original_url) AS hash',
    'source',
    '(xmax = 0) AS is_new',
    `${pgEscape(o.domain_slug)} AS domain_slug`,
    `${pgEscape(o.domain_label)} AS domain_label`,
    `${pgEscape(o.matched_role)} AS matched_role`,
    `${pgEscape(o.matched_alias)} AS matched_alias`,
    `${Math.round(Number(o.match_score || 0))} AS match_score`,
    `${pgEscape(o.keyword_hits || '')} AS keyword_hits`,
    `${Number(o.alias_count || 0)} AS alias_count`,
    `${pgEscape(o.telegram_chat_id || '')} AS telegram_chat_id`,
  ].join(', ');
  return `INSERT INTO jobs (${cols.join(',')}) VALUES (${vals.join(',')}) ON CONFLICT (original_url) DO UPDATE SET company=EXCLUDED.company, title=EXCLUDED.title, location=EXCLUDED.location, country=EXCLUDED.country, jd_full_text=EXCLUDED.jd_full_text, source=EXCLUDED.source, posted_date=COALESCE(EXCLUDED.posted_date, jobs.posted_date), match_score=EXCLUDED.match_score, job_type=EXCLUDED.job_type, is_graduate=EXCLUDED.is_graduate, updated_at=CURRENT_TIMESTAMP RETURNING ${returning};`;
}

