function normalizeText(v) {
  return String(v || '')
    .toLowerCase()
    .replace(/&/g, ' and ')
    .replace(/[._+/()-]/g, ' ')
    .replace(/[^a-z0-9#\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function stripTitleNoise(v) {
  return normalizeText(v)
    .replace(/\b(junior|jr|associate|graduate|entry level|early career|new grad|trainee|apprentice|remote|contract|freelance|i|ii)\b/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function containsPhrase(hay, phrase) {
  const h = ` ${normalizeText(hay)} `;
  const p = normalizeText(phrase);
  return p && h.includes(` ${p} `);
}

function enrichDomain(domain) {
  const rawAliases = new Set();
  for (const role of domain.coreRoles) {
    rawAliases.add(role);
    for (const prefix of ENTRY_TITLE_PREFIXES) {
      for (const suffix of ENTRY_TITLE_SUFFIXES) {
        rawAliases.add(`${prefix}${role}${suffix}`.trim());
      }
    }
  }
  const aliases = [...rawAliases].filter(Boolean);
  const aliasNeedles = [...new Set(aliases.map(stripTitleNoise).filter(v => v.length >= 4))];
  return {
    ...domain,
    aliases,
    aliasNeedles,
    aliasCount: aliases.length,
    normalizedInputs: [domain.slug, domain.label, ...domain.inputAliases].map(normalizeText),
    normalizedTerms: domain.terms.map(normalizeText),
  };
}

const ENRICHED_DOMAINS = DOMAIN_TAXONOMY.map(enrichDomain);

function resolveSelectedDomains(rawDomain) {
  const raw = normalizeText(rawDomain || 'AI, Machine Learning and GenAI');
  if (['all', 'all domains', 'all it', 'everything', 'any'].includes(raw)) {
    return ENRICHED_DOMAINS;
  }
  const exact = ENRICHED_DOMAINS.find(d => d.normalizedInputs.includes(raw));
  if (exact) return [exact];
  const fuzzy = ENRICHED_DOMAINS.find(d => d.normalizedInputs.some(alias => raw.includes(alias) || alias.includes(raw)));
  if (fuzzy) return [fuzzy];
  return [enrichDomain({
    slug: raw.replace(/[^a-z0-9]+/g, '_').replace(/^_+|_+$/g, '') || 'custom',
    label: rawDomain || 'Custom Domain',
    inputAliases: [rawDomain || 'custom'],
    searchQueries: [rawDomain || 'Software Engineer'],
    coreRoles: [rawDomain || 'Software Engineer'],
    terms: normalizeText(rawDomain || '').split(/\s+/).filter(t => t.length > 2),
  })];
}

function jobSeniorityBlocked(title, domainSlug, extraBlocklist) {
  const t = normalizeText(title);
  const hard = [
    /\bsenior\b/, /\bsr\b/, /\bstaff\b/, /\bprincipal\b/, /\blead\b/,
    /\bdirector\b/, /\bhead\b/, /\bvp\b/, /\bchief\b/, /\bcto\b/, /\bciso\b/,
    /\bengineering manager\b/, /\bsoftware development manager\b/, /\bteam manager\b/,
  ];
  if (hard.some(re => re.test(t))) return true;
  const cleanedBlocklist = (Array.isArray(extraBlocklist) ? extraBlocklist : [])
    .map(normalizeText)
    .filter(v => v && v !== 'manager');
  return cleanedBlocklist.some(word => containsPhrase(t, word));
}

function matchJobToDomains(job, selectedDomains) {
  const titleNorm = normalizeText(job.title);
  const titleBase = stripTitleNoise(job.title);
  const hay = `${titleNorm} ${normalizeText(job.jd_text)} ${normalizeText(job.company)} ${normalizeText(job.source)}`;
  let best = null;
  for (const domain of selectedDomains) {
    let bestAlias = '';
    let bestRole = '';
    let aliasScore = 0;
    for (const role of domain.coreRoles) {
      const r = stripTitleNoise(role);
      if (r && titleBase.includes(r)) {
        bestAlias = role;
        bestRole = role;
        aliasScore = Math.max(aliasScore, 78);
        break;
      }
    }
    if (!bestAlias) {
      for (const alias of domain.aliasNeedles) {
        if (alias.length >= 4 && (titleBase.includes(alias) || titleNorm.includes(alias))) {
          bestAlias = alias;
          bestRole = domain.coreRoles.find(role => stripTitleNoise(role) === alias) || alias;
          aliasScore = Math.max(aliasScore, 70);
          break;
        }
      }
    }
    const keywordHits = domain.normalizedTerms.filter(term => term.length >= 3 && containsPhrase(hay, term));
    const keywordScore = Math.min(25, keywordHits.length * 5);
    if (!bestAlias && keywordHits.length < 3) continue;
    const score = aliasScore + keywordScore;
    if (!best || score > best.match_score) {
      best = {
        domain_slug: domain.slug,
        domain_label: domain.label,
        matched_role: bestRole || domain.label,
        matched_alias: bestAlias || keywordHits.slice(0, 3).join(', '),
        match_score: Math.min(100, score),
        keyword_hits: keywordHits.slice(0, 12).join(', '),
        alias_count: domain.aliasCount,
      };
    }
  }
  return best;
}

