async function runLimited(tasks, limit) {
  const out = [];
  let idx = 0;
  async function worker() {
    while (idx < tasks.length) {
      const current = idx++;
      out[current] = await tasks[current]();
    }
  }
  await Promise.all(Array.from({ length: Math.min(limit, tasks.length) }, worker));
  return out;
}

function envValue(name, fallback = '') {
  try {
    const value = $env[name];
    return value === undefined || value === null || value === '' ? fallback : value;
  } catch (e) {
    return fallback;
  }
}

function envNumber(name, fallback, min, max) {
  const raw = envValue(name, fallback);
  const n = Number(raw === undefined || raw === null || raw === '' ? fallback : raw);
  if (!Number.isFinite(n)) return fallback;
  return Math.max(min, Math.min(max, Math.floor(n)));
}

function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

function retryDelayMs(attempt, baseMs) {
  const jitter = Math.floor(Math.random() * Math.min(500, baseMs));
  return Math.min(15000, baseMs * Math.pow(2, attempt - 1) + jitter);
}

function statusFromResponse(res) {
  const status = Number(
    res?.statusCode ||
    res?.status ||
    res?.body?.statusCode ||
    res?.body?.status ||
    res?.body?.error?.status ||
    0
  );
  return Number.isFinite(status) ? status : 0;
}

function bodyFromResponse(res) {
  return res && Object.prototype.hasOwnProperty.call(res, 'body') ? res.body : res;
}

function isRetryableStatus(status) {
  return [408, 425, 429, 500, 502, 503, 504].includes(Number(status));
}

