const safe = async (name, opts) => {
  let lastError = '';
  let lastStatus = 0;
  for (let attempt = 1; attempt <= sourceRetries + 1; attempt++) {
    try {
      const res = await helpers.httpRequest({
        ...opts,
        json: true,
        returnFullResponse: true,
        ignoreHttpStatusErrors: true,
        timeout: sourceTimeoutMs,
      });
      const status = statusFromResponse(res);
      const data = bodyFromResponse(res);
      lastStatus = status;
      if (isRetryableStatus(status) && attempt <= sourceRetries) {
        await sleep(retryDelayMs(attempt, sourceRetryBaseMs));
        continue;
      }
      const ok = !status || (status >= 200 && status < 400);
      return {
        source: name,
        ok,
        status,
        attempts: attempt,
        data,
        error: ok ? '' : `http_${status || 'error'}`,
      };
    } catch (e) {
      lastError = String(e).slice(0, 200);
      if (attempt <= sourceRetries) {
        await sleep(retryDelayMs(attempt, sourceRetryBaseMs));
        continue;
      }
    }
  }
  return { source: name, ok: false, status: lastStatus, attempts: sourceRetries + 1, error: lastError || `http_${lastStatus || 'error'}` };
};

