function normalizeText(v) {
  return String(v || '')
    .toLowerCase()
    .replace(/&/g, ' and ')
    .replace(/[^a-z0-9\s.-]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function safeUrl(v) {
  const raw = String(v || '').trim();
  const m = raw.match(/^(https?):\/\/([^/?#\s]+)([^\s]*)?$/i);
  if (!m) return null;
  const protocol = `${m[1].toLowerCase()}:`;
  const host = m[2].replace(/^[^@]+@/, '');
  const hostname = host.split(':')[0].toLowerCase();
  if (!hostname || !['http:', 'https:'].includes(protocol)) return null;
  return { protocol, hostname, href: raw, toString: () => raw };
}

function baseDomain(hostname) {
  const h = String(hostname || '').toLowerCase().replace(/^www\./, '');
  const parts = h.split('.').filter(Boolean);
  if (parts.length <= 2) return h;
  const twoPartTlds = new Set(['co.uk', 'com.au', 'com.br', 'co.jp', 'co.in', 'com.sg', 'com.mx']);
  const lastTwo = parts.slice(-2).join('.');
  if (twoPartTlds.has(lastTwo) && parts.length >= 3) return parts.slice(-3).join('.');
  return parts.slice(-2).join('.');
}

function cleanCompanySlug(company) {
  const cleaned = normalizeText(company)
    .replace(/\b(inc|incorporated|ltd|limited|llc|plc|gmbh|sa|ag|bv|company|technologies|technology|software|labs|ai)\b/g, ' ')
    .replace(/\s+/g, '')
    .replace(/[^a-z0-9-]/g, '');
  return cleaned || normalizeText(company).replace(/\s+/g, '').replace(/[^a-z0-9-]/g, '');
}

