    'greenhouse.io', 'lever.co', 'ashbyhq.com', 'workdayjobs.com', 'myworkdayjobs.com',
    'smartrecruiters.com', 'bamboohr.com', 'jobvite.com', 'icims.com', 'remoteok.com',
    'adzuna.com', 'jooble.org', 'serpapi.com',
  ];
  if (host && !atsHosts.some(ats => host.endsWith(ats))) return host;
  const slug = cleanCompanySlug(company);
  return slug ? `${slug}.com` : '';
}

function sourceQuality(source, url) {
  const s = normalizeText(source);
  const host = safeUrl(url)?.hostname || '';
  if (s.startsWith('gh') || s.startsWith('lever') || s.startsWith('ashby')) return 'direct_ats_board';
  if (s.includes('remoteok')) return 'remote_board';
  if (s.includes('adzuna') || s.includes('jooble') || s.includes('serpapi')) return 'aggregator';
  if (s.includes('sgai')) return 'ai_scraped_company_page';
  if (/greenhouse|lever|ashby|workday|smartrecruiters/i.test(host)) return 'direct_ats_board';
  return 'unknown';
}

function calcApplyReadyScore(job) {
  let score = 0;
  score += Math.min(45, Math.max(0, Number(job.match_score || 0) * 0.45));
  if (job.link_ok) score += 30;
  if (job.source_quality === 'direct_ats_board') score += 15;
  else if (job.source_quality === 'ai_scraped_company_page') score += 10;
  else if (job.source_quality === 'remote_board') score += 8;
  else if (job.source_quality === 'aggregator') score += 3;
  if (job.company_domain) score += 5;
  if (job.final_url && job.final_url !== job.url) score += 5;
  return Math.max(0, Math.min(100, Math.round(score)));
}

async function runLimited(items, limit, fn) {
  const out = [];
  let idx = 0;
  async function worker() {
    while (idx < items.length) {
      const current = idx++;
      out[current] = await fn(items[current], current);
    }
  }
  await Promise.all(Array.from({ length: Math.min(limit, items.length) }, worker));
  return out;
}

function envValue(name, fallback = '') {
  try {
    const value = $env[name];
    return value === undefined || value === null || value === '' ? fallback : value;
  } catch (e) {
    return fallback;
  }
}

function envNumber(name, fallback, min, max) {
  const raw = envValue(name, fallback);
  const n = Number(raw === undefined || raw === null || raw === '' ? fallback : raw);
  if (!Number.isFinite(n)) return fallback;
  return Math.max(min, Math.min(max, Math.floor(n)));
}

function envBool(name, fallback) {
  const raw = envValue(name, fallback ? 'true' : 'false');
  if (raw === undefined || raw === null || raw === '') return fallback;
  return !['0', 'false', 'no', 'off'].includes(String(raw).toLowerCase());
}

function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

function retryDelayMs(attempt, baseMs) {
  const jitter = Math.floor(Math.random() * Math.min(500, baseMs));
  return Math.min(12000, baseMs * Math.pow(2, attempt - 1) + jitter);
}

function isRetryableStatus(status) {
  return [408, 425, 429, 500, 502, 503, 504].includes(Number(status));
}

const helpers = this.helpers;
const verifyConcurrency = envNumber('VERIFY_CONCURRENCY', 6, 1, 20);
const verifyRetries = envNumber('VERIFY_RETRIES', 2, 0, 5);
const verifyTimeoutMs = envNumber('VERIFY_TIMEOUT_MS', 15000, 3000, 60000);
const verifyRetryBaseMs = envNumber('VERIFY_RETRY_BASE_MS', 600, 100, 10000);
const verifyCompanyLinks = envBool('VERIFY_COMPANY_LINKS', true);
const companyLinkVerifyLimit = envNumber('COMPANY_LINK_VERIFY_LIMIT', 60, 0, 500);
const publicUrlCache = new Map();

async function verifyJobUrl(url) {
  const u = safeUrl(url);
  if (!u) {
    return { link_ok: false, link_status: 'invalid_url', link_status_code: 0, final_url: url || '' };
  }

  const request = async method => {
    let lastError = '';
    let lastStatus = 0;
    for (let attempt = 1; attempt <= verifyRetries + 1; attempt++) {
      try {
        const res = await helpers.httpRequest({
          url: u.toString(),
          method,
          json: false,
          returnFullResponse: true,
          ignoreHttpStatusErrors: true,
          timeout: verifyTimeoutMs,
          headers: {
            'User-Agent': 'job-radar-link-verifier/1.0',
            'Accept': 'text/html,application/xhtml+xml,application/json;q=0.9,*/*;q=0.8',
          },
        });
        const statusCode = Number(res?.statusCode || res?.status || 0);
        lastStatus = statusCode;
        if (isRetryableStatus(statusCode) && attempt <= verifyRetries) {
          await sleep(retryDelayMs(attempt, verifyRetryBaseMs));
          continue;
        }
        const body = typeof res?.body === 'string' ? res.body.slice(0, 1200) : '';
        const finalUrl = res?.request?.uri?.href || res?.responseUrl || res?.url || u.toString();
        return { ok: true, statusCode, body, finalUrl, attempts: attempt, method };
      } catch (e) {
        lastError = String(e).slice(0, 160);
        if (attempt <= verifyRetries) {
          await sleep(retryDelayMs(attempt, verifyRetryBaseMs));
          continue;
        }
      }
    }
    return { ok: false, statusCode: lastStatus, error: lastError || `http_${lastStatus || 'error'}`, finalUrl: u.toString(), body: '', attempts: verifyRetries + 1, method };
  };

  let r = await request('HEAD');
  if (!r.ok || !r.statusCode || r.statusCode === 405 || r.statusCode === 403 || r.statusCode >= 400) {
    const getResult = await request('GET');
    if (getResult.ok || getResult.statusCode || getResult.body) r = getResult;
  }

  const expiredText = /job no longer|position has been filled|not found|no longer accepting|closed|expired/i.test(r.body || '');
  const linkOk = r.statusCode >= 200 && r.statusCode < 400 && !expiredText;
  return {
    link_ok: linkOk,
    link_status: linkOk ? 'live' : (expiredText ? 'expired_or_closed' : `http_${r.statusCode || 'error'}`),
    link_status_code: r.statusCode || 0,
    final_url: r.finalUrl || u.toString(),
    link_error: r.error || '',
    link_attempts: r.attempts || 1,
    link_check_method: r.method || '',
  };
}

async function verifyPublicUrl(url) {
  const u = safeUrl(url);
  if (!u) return { ok: false, status: 'invalid_url', status_code: 0, final_url: url || '' };
  const key = u.toString();
  if (!verifyCompanyLinks) return { ok: null, status: 'skipped_disabled', status_code: 0, final_url: key };
  if (!publicUrlCache.has(key)) {
    if (companyLinkVerifyLimit <= 0 || publicUrlCache.size >= companyLinkVerifyLimit) {
      return { ok: null, status: 'skipped_limit', status_code: 0, final_url: key };
    }
    publicUrlCache.set(key, verifyJobUrl(key));
  }
  const v = await publicUrlCache.get(key);
  return { ok: v.link_ok, status: v.link_status, status_code: v.link_status_code, final_url: v.final_url };
}

function publicFields(prefix, v) {
  return {
    [`${prefix}_ok`]: v.ok,
    [`${prefix}_status`]: v.status,
    [`${prefix}_status_code`]: v.status_code,
    [`${prefix}_final_url`]: v.final_url,
  };
}

const items = $input.all().map(i => i.json).filter(j => j && j.title && j.url);
if (items.length === 0) {
  return [{ json: { skip: true, reason: 'no_jobs_after_upsert', count: 0 } }];
}

const enriched = await runLimited(items, verifyConcurrency, async job => {
  const verify = await verifyJobUrl(job.url);
  const finalUrl = verify.final_url || job.url;
  const companyDomain = inferCompanyDomain(finalUrl, job.company);
  const companyHomepage = companyDomain ? `https://${companyDomain}` : '';
  const companyCareers = companyHomepage ? `${companyHomepage}/careers` : '';
  const companyJobs = companyHomepage ? `${companyHomepage}/jobs` : '';
  const companyContact = companyHomepage ? `${companyHomepage}/contact` : '';
  const quality = sourceQuality(job.source, finalUrl);
  const [homepageCheck, careersCheck, jobsCheck, contactCheck] = await Promise.all([
    verifyPublicUrl(companyHomepage),
    verifyPublicUrl(companyCareers),
    verifyPublicUrl(companyJobs),
    verifyPublicUrl(companyContact),
  ]);
  const out = {
    ...job,
    ...verify,
    source_quality: quality,
    company_domain: companyDomain,
    company_homepage_url: companyHomepage,
    company_careers_url: companyCareers,
    company_jobs_url: companyJobs,
    company_contact_url: companyContact,
    ...publicFields('company_homepage', homepageCheck),
    ...publicFields('company_careers', careersCheck),
    ...publicFields('company_jobs', jobsCheck),
    ...publicFields('company_contact', contactCheck),
    company_linkedin_search_url: `https://www.linkedin.com/search/results/companies/?keywords=${encodeURIComponent(job.company || '')}`,
    company_google_jobs_search_url: `https://www.google.com/search?q=${encodeURIComponent(`${job.company || ''} careers ${job.title || ''}`)}`,
    contact_policy: 'company_pages_only_no_personal_email_scraping',
    crm_status: verify.link_ok ? 'ready_to_review' : 'needs_link_review',
    next_action: verify.link_ok ? 'review_apply_page' : 'check_or_replace_link',
    discovered_at: new Date().toISOString(),
    _verify_config: `verify_concurrency=${verifyConcurrency}; verify_retries=${verifyRetries}; timeout_ms=${verifyTimeoutMs}; verify_company_links=${verifyCompanyLinks}; company_link_verify_limit=${companyLinkVerifyLimit}`,
  };
  out.apply_ready_score = calcApplyReadyScore(out);
  return out;
});

enriched.sort((a, b) => (b.apply_ready_score - a.apply_ready_score) || (b.match_score - a.match_score));
return enriched.map(j => ({ json: j }));
